#endif

/* Taken from the current format defined in
 * include/trace/events/ib_umad.h
 * and
 * /sys/kernel/tracing/events/ib_umad/ib_umad_read/format
 * /sys/kernel/tracing/events/ib_umad/ib_umad_write/format
 */
